const payload = ($input.first().json.payload ?? $input.first().json);
if (!payload.action) return [{ json: { status: 'error', event: {}, error: 'action is required' } }];
const needsApproval = payload.action === 'cancel_event' || (payload.action === 'create_event' && Array.isArray(payload.attendees) && payload.attendees.length > 0);
return [{ json: { status: needsApproval ? 'pending_approval' : 'success', event: { action: payload.action, title: payload.title ?? null, date_range: payload.date_range ?? {}, attendees: payload.attendees ?? [] }, approval_required: needsApproval, note: 'Calendar credential placeholder.' } }];
